INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dadc676c-ec7c-4645-a7c6-759360a99282', $q$Rolling funding capacity$q$, $q$An ongoing, renewable capital line that businesses can draw against repeatedly as they repay, rather than reapplying for each funding need.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dadc676c-ec7c-4645-a7c6-759360a99282', $q$Fixed funding capacity$q$, $q$A one-time lump-sum advance sized for a specific inventory purchase, marketing push, or growth initiative.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dadc676c-ec7c-4645-a7c6-759360a99282', $q$Invoice funding$q$, $q$Advances against outstanding B2B invoices so ecommerce sellers with wholesale or marketplace receivables aren't stuck waiting on payment terms.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dadc676c-ec7c-4645-a7c6-759360a99282', $q$Ecommerce and payments integrations$q$, $q$Direct connections to Shopify, Amazon, BigCommerce, Square, Stripe, and PayPal let Clearco underwrite based on real transaction history.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dadc676c-ec7c-4645-a7c6-759360a99282', $q$Fast funding decisions$q$, $q$Funding offers can be issued in as little as 24 hours after a business connects its data, far faster than typical bank underwriting.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dadc676c-ec7c-4645-a7c6-759360a99282', $q$No equity or personal guarantees$q$, $q$Capital is provided without taking board seats, ownership stakes, or requiring personal guarantees from founders.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dadc676c-ec7c-4645-a7c6-759360a99282', $q$Revenue-based repayment$q$, $q$Repayment is collected as a percentage of ongoing revenue, so payments flex up or down with the business's actual sales.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dadc676c-ec7c-4645-a7c6-759360a99282', $q$Early repayment savings$q$, $q$Businesses that repay advances ahead of schedule can reduce the total fee owed on the capital.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dadc676c-ec7c-4645-a7c6-759360a99282', $q$No equity dilution or board seats required to access capital$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dadc676c-ec7c-4645-a7c6-759360a99282', $q$Funding decisions can be made in as little as 24 hours$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dadc676c-ec7c-4645-a7c6-759360a99282', $q$Repayment scales with revenue rather than a fixed monthly payment$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dadc676c-ec7c-4645-a7c6-759360a99282', $q$Deep integrations with the ecommerce platforms brands already use$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dadc676c-ec7c-4645-a7c6-759360a99282', $q$Track record of over $3 billion deployed to 10,000+ businesses$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('dadc676c-ec7c-4645-a7c6-759360a99282', $q$Not a fit for pre-revenue startups or businesses without trackable online sales history$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('dadc676c-ec7c-4645-a7c6-759360a99282', $q$Requires connecting sensitive sales and banking data for underwriting$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('dadc676c-ec7c-4645-a7c6-759360a99282', $q$Total cost of capital (flat fee) isn't published and varies per deal$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('dadc676c-ec7c-4645-a7c6-759360a99282', $q$Limited mainly to ecommerce and consumer brands rather than all business types$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dadc676c-ec7c-4645-a7c6-759360a99282', $q$What is Clearco and how is it different from a bank loan?$q$, $q$Clearco is a revenue-based financing provider for ecommerce brands. Instead of a fixed-rate loan or line of credit underwritten on credit history, Clearco advances capital based on a business's actual sales data and collects repayment as a percentage of revenue until the advance plus a flat fee is repaid.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dadc676c-ec7c-4645-a7c6-759360a99282', $q$Does Clearco take equity in exchange for funding?$q$, $q$No. Clearco's financing is non-dilutive: it does not take equity, board seats, or require personal guarantees from founders.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dadc676c-ec7c-4645-a7c6-759360a99282', $q$How fast can a business get funded through Clearco?$q$, $q$Once a business connects its sales, payments, and ad accounts, Clearco can issue a funding decision in as little as 24 hours, though the exact timeline depends on the completeness of the data provided.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dadc676c-ec7c-4645-a7c6-759360a99282', $q$What platforms does Clearco integrate with?$q$, $q$Clearco connects with major ecommerce and payments platforms including Shopify, Amazon, BigCommerce, Square, Stripe, and PayPal to evaluate revenue and underwrite funding offers.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dadc676c-ec7c-4645-a7c6-759360a99282', $q$How much does Clearco funding cost?$q$, $q$Clearco charges a flat fee on the capital advanced rather than a traditional interest rate. The exact fee depends on the funding amount, revenue history, and repayment terms, and is only shown after a business applies and connects its data.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dadc676c-ec7c-4645-a7c6-759360a99282', $q$Who is Clearco best suited for?$q$, $q$Clearco is designed for ecommerce and consumer brands with consistent, trackable online revenue that need capital for inventory, advertising, or working capital without giving up equity.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('dadc676c-ec7c-4645-a7c6-759360a99282', $q$Inventory financing for DTC brands$q$, $q$Direct-to-consumer brands use Clearco advances to buy inventory ahead of demand spikes or seasonal peaks without tying up cash flow.$q$, $q$Direct-to-consumer and Shopify-based ecommerce brands$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('dadc676c-ec7c-4645-a7c6-759360a99282', $q$Performance marketing spend$q$, $q$Brands fund paid advertising campaigns on channels like Meta and Google using Clearco capital, then repay as the campaigns drive incremental revenue.$q$, $q$Ecommerce marketing and growth teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('dadc676c-ec7c-4645-a7c6-759360a99282', $q$Working capital for B2B ecommerce sellers$q$, $q$Wholesale and marketplace sellers use invoice funding to bridge the gap between fulfilling orders and receiving payment on outstanding invoices.$q$, $q$B2B ecommerce and wholesale sellers$q$, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('dadc676c-ec7c-4645-a7c6-759360a99282', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Clearco was founded in 2015 in Toronto by Andrew D'Souza and Michele Romanow as Clearbanc, rebranding to Clearco in 2021. The company built its business around a simple premise: ecommerce founders were routinely giving up equity to venture investors just to fund inventory and ad spend, expenses that are predictable and directly tied to revenue. Clearco replaced that model with revenue-based financing, advancing capital in exchange for a fixed fee and a share of future revenue rather than an ownership stake.$q$, $q$Since launch, Clearco has funded more than 10,000 ecommerce and consumer brands and deployed over $3 billion in capital. It underwrites deals by connecting directly to a company's sales, ad spend, and payment platforms, which lets it evaluate and approve funding requests far faster than a conventional bank loan process.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('dadc676c-ec7c-4645-a7c6-759360a99282', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Clearco offers several funding structures: rolling funding capacity that renews as it's repaid, fixed funding capacity for one-time capital needs, cash advances, and invoice funding for businesses waiting on B2B receivables. Funding decisions are typically made within 24 hours once a business connects its sales and payment accounts.$q$, $q$The platform integrates with the ecommerce and payments tools most DTC brands already use, including Shopify, Amazon, BigCommerce, Square, Stripe, and PayPal, pulling transaction history automatically instead of requiring manual financial statements. Repayment scales with revenue, businesses pay more when sales are strong and less during slower periods, and early repayment can reduce the total fee owed.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('dadc676c-ec7c-4645-a7c6-759360a99282', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Clearco does not use a subscription pricing model. Instead, it charges a flat fee on the capital advanced, calculated per offer based on the funding amount, the business's revenue history, and the agreed repayment terms, so there is no single published "starting price." Businesses see their specific fee and repayment terms only after connecting their sales data and receiving a funding offer.$q$, $q$Because pricing is individualized, prospective customers typically need to apply and link their store or payment accounts to get an exact quote. There are no setup fees, no equity given up, and no personal guarantees required, but the total cost of capital varies by deal.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('dadc676c-ec7c-4645-a7c6-759360a99282', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f1140885-6be9-4e12-8a14-e60b800377b9', $q$Experiment tracking$q$, $q$Automatic logging of hyperparameters, metrics, code, and artifacts for every training run, with minimal instrumentation required.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f1140885-6be9-4e12-8a14-e60b800377b9', $q$Data and model versioning$q$, $q$A built-in repository for datasets and model artifacts that tracks lineage across experiments.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f1140885-6be9-4e12-8a14-e60b800377b9', $q$Pipeline orchestration$q$, $q$Define, schedule, and run multi-step ML pipelines, with triggers available on paid tiers.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f1140885-6be9-4e12-8a14-e60b800377b9', $q$Compute orchestration and auto-scaling$q$, $q$An agent-based queueing system that runs jobs across available compute, with auto-scaling across AWS, GCP, and Azure on the Pro tier and above.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f1140885-6be9-4e12-8a14-e60b800377b9', $q$Hyperparameter optimization$q$, $q$Automated search over hyperparameters to find better-performing model configurations.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f1140885-6be9-4e12-8a14-e60b800377b9', $q$Model serving$q$, $q$Deploy trained models for inference as part of the same platform used for training and experiment tracking.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f1140885-6be9-4e12-8a14-e60b800377b9', $q$Self-hosted or managed deployment$q$, $q$Run the open-source edition on your own infrastructure, or use ClearML's hosted SaaS or enterprise VPC/on-prem/air-gapped options.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f1140885-6be9-4e12-8a14-e60b800377b9', $q$Enterprise access controls$q$, $q$SSO, role-based access control, and configuration vaults available on Enterprise plans for regulated environments.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f1140885-6be9-4e12-8a14-e60b800377b9', $q$Open-source core is free and self-hostable with production-grade features$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f1140885-6be9-4e12-8a14-e60b800377b9', $q$Covers experiment tracking, data versioning, and orchestration in one platform$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f1140885-6be9-4e12-8a14-e60b800377b9', $q$Flexible deployment from self-hosted to fully managed enterprise VPC/on-prem$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f1140885-6be9-4e12-8a14-e60b800377b9', $q$Pro tier is affordably priced per user relative to enterprise-only MLOps competitors$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f1140885-6be9-4e12-8a14-e60b800377b9', $q$Free Community tier caps out at 3 users, limiting it to small teams$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f1140885-6be9-4e12-8a14-e60b800377b9', $q$Pay-as-you-go overage charges on storage, metrics, and API calls can add up for heavy usage$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f1140885-6be9-4e12-8a14-e60b800377b9', $q$Enterprise and Scale pricing is not public and requires a custom quote$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f1140885-6be9-4e12-8a14-e60b800377b9', $q$Feature depth across so many capabilities means a learning curve for teams new to MLOps$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f1140885-6be9-4e12-8a14-e60b800377b9', $q$Is ClearML open source?$q$, $q$Yes. ClearML's core platform is open source and available on GitHub, and can be self-hosted for free with production-grade experiment tracking, data versioning, pipeline, and orchestration features.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f1140885-6be9-4e12-8a14-e60b800377b9', $q$How much does ClearML cost?$q$, $q$The self-hosted open-source edition is free. The hosted Pro plan costs $15 per user per month for up to 10 users, while Scale and Enterprise plans for larger GPU deployments use custom quoted pricing.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f1140885-6be9-4e12-8a14-e60b800377b9', $q$What is the difference between ClearML Community and Pro plans?$q$, $q$Community is free for up to 3 users with core experiment tracking and pipeline features. Pro adds cloud auto-scaling across AWS, GCP, and Azure, hyperparameter optimization, pipeline triggers, and dashboards for up to 10 users.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f1140885-6be9-4e12-8a14-e60b800377b9', $q$Can ClearML be self-hosted or run on-premises?$q$, $q$Yes. In addition to the free open-source self-hosted edition, ClearML offers Enterprise deployment options including VPC, on-premises, hybrid, and air-gapped installations.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f1140885-6be9-4e12-8a14-e60b800377b9', $q$Who uses ClearML?$q$, $q$ClearML is used by machine learning engineers, data scientists, and MLOps teams to track experiments, version datasets and models, and orchestrate training and inference pipelines across cloud or on-premises compute.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f1140885-6be9-4e12-8a14-e60b800377b9', $q$What are ClearML's main alternatives?$q$, $q$Common alternatives include Weights & Biases, MLflow, Neptune.ai, and Comet, though ClearML differentiates itself by also including pipeline and compute orchestration in its open-source offering.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f1140885-6be9-4e12-8a14-e60b800377b9', $q$Experiment tracking for research teams$q$, $q$ML researchers log and compare training runs automatically, making results reproducible across a team without manual spreadsheets.$q$, $q$ML researchers and data scientists$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f1140885-6be9-4e12-8a14-e60b800377b9', $q$GPU cluster orchestration$q$, $q$MLOps teams queue and auto-scale training jobs across cloud or on-prem GPU clusters using ClearML's agent-based orchestration.$q$, $q$MLOps and infrastructure engineers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f1140885-6be9-4e12-8a14-e60b800377b9', $q$Regulated or air-gapped ML environments$q$, $q$Organizations with strict data residency requirements self-host ClearML on-premises or in an air-gapped enterprise deployment.$q$, $q$Enterprises in regulated industries$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f1140885-6be9-4e12-8a14-e60b800377b9', $q$Community$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Up to 3 users","100GB artifact storage","1GB metric events","1M API calls/month","Experiment tracking, data management, pipelines"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f1140885-6be9-4e12-8a14-e60b800377b9', $q$Pro$q$, $q$$15/user/month$q$, $q$monthly$q$, NULL, $q$["Up to 10 users","Cloud auto-scaling (AWS, GCP, Azure)","Hyperparameter optimization","Pipeline triggers and dashboards","Pay-as-you-go overage on storage, metrics, API calls, compute"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f1140885-6be9-4e12-8a14-e60b800377b9', $q$Scale$q$, $q$Custom$q$, $q$custom$q$, NULL, $q$["For 8-48 GPU deployments","VPC-only","Hyper-datasets, fine-tuning, IDE launcher","Kubernetes integration, task scheduling"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f1140885-6be9-4e12-8a14-e60b800377b9', $q$Enterprise$q$, $q$Custom$q$, $q$custom$q$, NULL, $q$["On-prem/air-gapped/multi-cloud options","SSO, RBAC, configuration vault","Slurm/PBS and LDAP integration","White-glove support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f1140885-6be9-4e12-8a14-e60b800377b9', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$ClearML was founded in 2016 in Tel Aviv, Israel, and built its reputation as one of the more complete open-source MLOps toolkits available, covering experiment tracking, data versioning, pipeline orchestration, and compute-resource management in one project rather than requiring teams to combine several separate tools. The core codebase is open source on GitHub, and the company also sells hosted and enterprise versions for teams that want a managed platform or additional controls.$q$, $q$ClearML is aimed at machine learning engineers and MLOps teams running training and inference workloads, whether on a handful of GPUs or across large multi-cloud clusters. Its open-source, self-hostable nature makes it a common choice for teams with strict data-residency or air-gapped infrastructure requirements.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f1140885-6be9-4e12-8a14-e60b800377b9', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The platform automatically logs experiments, hyperparameters, metrics, and artifacts with minimal code changes, and maintains a versioned model and dataset repository so results can be reproduced later. Pipelines can be defined, orchestrated, and scheduled directly in ClearML, and an agent-based system queues and executes jobs across whatever compute is available, including auto-scaling across AWS, GCP, and Azure on paid tiers.$q$, $q$Higher tiers add hyperparameter optimization, pipeline triggers, and dashboards for team-wide visibility, while enterprise deployments add Kubernetes and Slurm/PBS integration, fractional GPU allocation, vector database integration for LLM workflows, SSO, and role-based access control for larger or regulated organizations.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f1140885-6be9-4e12-8a14-e60b800377b9', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$ClearML's Community plan is free for up to three users and includes core experiment tracking, data management, and pipeline features with 100GB of artifact storage and 1 million API calls per month. The Pro plan costs $15 per user per month for up to ten users and adds cloud auto-scaling and hyperparameter optimization, with extra storage, metrics, and API usage billed pay-as-you-go beyond the included allotment.$q$, $q$Scale and Enterprise plans are custom-quoted and intended for organizations running dedicated GPU infrastructure, whether in their own VPC, on-premises, or in a hybrid setup, with pricing based on compute scale and the specific enterprise features required rather than a flat per-user rate.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f1140885-6be9-4e12-8a14-e60b800377b9', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
