INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7de794bf-b842-4128-82f7-b18545f5a992', $q$Content grading and term recommendations$q$, $q$Analyzes top-ranking pages for a target keyword and generates a content grade plus recommended terms and related topics.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7de794bf-b842-4128-82f7-b18545f5a992', $q$Google Docs integration$q$, $q$Live content scoring and term suggestions appear directly inside Google Docs while writers draft.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7de794bf-b842-4128-82f7-b18545f5a992', $q$WordPress integration$q$, $q$Optimize and grade content directly within WordPress without exporting to a separate tool.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7de794bf-b842-4128-82f7-b18545f5a992', $q$AI search prompt tracking$q$, $q$Tracks how a brand or page appears in ChatGPT and Gemini responses for a defined set of prompts.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7de794bf-b842-4128-82f7-b18545f5a992', $q$Brand visibility monitoring$q$, $q$Monitors how often and how favorably a brand is mentioned in AI-generated answers.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7de794bf-b842-4128-82f7-b18545f5a992', $q$Topic and query analysis$q$, $q$Surfaces related topics, questions, and subtopics competitors cover that a piece of content may be missing.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7de794bf-b842-4128-82f7-b18545f5a992', $q$Unlimited sharing$q$, $q$Reports and content grades can be shared across a team or with external writers at no extra cost on any plan.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7de794bf-b842-4128-82f7-b18545f5a992', $q$Strong focus on content quality and semantic relevance rather than generic keyword stuffing$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7de794bf-b842-4128-82f7-b18545f5a992', $q$Native Google Docs and WordPress integrations fit existing writer workflows$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7de794bf-b842-4128-82f7-b18545f5a992', $q$Extended into AI search visibility tracking (ChatGPT, Gemini) ahead of many competitors$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7de794bf-b842-4128-82f7-b18545f5a992', $q$Used and trusted by large enterprise content teams (Adobe, HubSpot, Shopify)$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7de794bf-b842-4128-82f7-b18545f5a992', $q$Starting price of $129/month is higher than several content-optimization competitors$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7de794bf-b842-4128-82f7-b18545f5a992', $q$Page and prompt limits on lower tiers can be restrictive for high-volume content teams$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7de794bf-b842-4128-82f7-b18545f5a992', $q$Enterprise pricing is not public and requires a sales conversation$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7de794bf-b842-4128-82f7-b18545f5a992', $q$Focused narrowly on content optimization rather than full-suite SEO (backlinks, technical audits)$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7de794bf-b842-4128-82f7-b18545f5a992', $q$What does Clearscope do?$q$, $q$Clearscope analyzes top-ranking search results for a target keyword and gives writers a content grade, recommended terms, and related topics to help their content rank better in Google and be surfaced in AI answer engines.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7de794bf-b842-4128-82f7-b18545f5a992', $q$How much does Clearscope cost?$q$, $q$Clearscope starts at $129/month for the Essentials plan, with a Business plan at $399/month and custom Enterprise pricing for larger organizations.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7de794bf-b842-4128-82f7-b18545f5a992', $q$Does Clearscope integrate with Google Docs and WordPress?$q$, $q$Yes, Clearscope integrates directly with both Google Docs and WordPress so writers can see optimization scores and recommendations while writing.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7de794bf-b842-4128-82f7-b18545f5a992', $q$Can Clearscope track AI search visibility, not just Google rankings?$q$, $q$Yes. Clearscope tracks prompts across ChatGPT and Gemini to monitor how often and how a brand or page is referenced in AI-generated answers, in addition to traditional search optimization.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7de794bf-b842-4128-82f7-b18545f5a992', $q$Who is Clearscope built for?$q$, $q$Clearscope is built for content marketers, SEO teams, and agencies that produce ongoing organic-search content and need a structured, data-driven way to brief and grade writers.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7de794bf-b842-4128-82f7-b18545f5a992', $q$What are alternatives to Clearscope?$q$, $q$Common alternatives in the content optimization space include Surfer SEO, MarketMuse, and Frase.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7de794bf-b842-4128-82f7-b18545f5a992', $q$SEO content briefs at scale$q$, $q$Content teams generate data-backed briefs with target terms and topics for freelance or in-house writers before drafting begins.$q$, $q$Content marketing and SEO teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7de794bf-b842-4128-82f7-b18545f5a992', $q$Content audits and refreshes$q$, $q$Teams re-grade existing pages against current top-ranking competitors to identify gaps and refresh underperforming content.$q$, $q$SEO specialists and content strategists$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7de794bf-b842-4128-82f7-b18545f5a992', $q$AI answer engine visibility tracking$q$, $q$Brands track how often they're cited in ChatGPT and Gemini responses for key prompts and adjust content to improve visibility.$q$, $q$Marketing and brand visibility teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7de794bf-b842-4128-82f7-b18545f5a992', $q$Essentials$q$, $q$$129/month$q$, $q$monthly$q$, NULL, $q$["50 tracked prompts","50 pages","20 monthly topic explorations","20 monthly drafts"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7de794bf-b842-4128-82f7-b18545f5a992', $q$Business$q$, $q$$399/month$q$, $q$monthly$q$, NULL, $q$["300 tracked prompts","300 pages","50 monthly topic explorations","20 monthly drafts","Dedicated account manager"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7de794bf-b842-4128-82f7-b18545f5a992', $q$Enterprise$q$, $q$Custom$q$, $q$custom$q$, NULL, $q$["Everything in Business","Custom credits and agreements","Crawler whitelisting","Single sign-on (SSO)"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7de794bf-b842-4128-82f7-b18545f5a992', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Clearscope was founded in 2016 by Bernard Huang and Kevin Su to help content teams write pages that are more likely to rank for a target search query, using data pulled from the pages already ranking well rather than generic SEO checklists. The company has since expanded its focus beyond traditional Google rankings to also track how brands and content appear in AI-generated answers from tools like ChatGPT and Gemini.$q$, $q$The platform is built around a simple workflow: enter a target keyword, get a content report with a grade and recommended terms based on top-ranking competitors, then write or revise content directly in Google Docs or WordPress while Clearscope scores it in real time.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7de794bf-b842-4128-82f7-b18545f5a992', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Clearscope generates a content grade and term recommendations by analyzing top-ranking pages for a given keyword, and surfaces related topics and questions writers should address to match search intent. Its Google Docs and WordPress integrations let writers see live optimization feedback without leaving their normal writing tools.$q$, $q$Newer capabilities extend beyond classic SEO into AI search visibility, including tracking how often a brand or page is referenced in ChatGPT and Gemini responses for tracked prompts, along with query analysis and AI-driven content recommendations aimed at improving that visibility.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7de794bf-b842-4128-82f7-b18545f5a992', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Clearscope offers three subscription tiers billed monthly: Essentials at $129/month (50 tracked prompts, 50 pages, 20 topic explorations, 20 drafts), Business at $399/month (300 tracked prompts, 300 pages, a dedicated account manager), and Enterprise at custom pricing (adds SSO, crawler whitelisting, and custom agreements).$q$, $q$All tiers include prompt tracking across ChatGPT and Gemini, brand visibility monitoring, and unlimited sharing with no long-term contract required; additional pages and drafts beyond a plan's limits are available as paid add-ons.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7de794bf-b842-4128-82f7-b18545f5a992', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7de794bf-b842-4128-82f7-b18545f5a992', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('84902cee-488e-4583-aad3-f2fbf318cb9e', $q$Prebuilt sign-up and sign-in UI components$q$, $q$Drop-in, customizable components for authentication flows that can be styled to match an application without building UI from scratch.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('84902cee-488e-4583-aad3-f2fbf318cb9e', $q$Multi-factor authentication$q$, $q$Built-in MFA options to add an additional verification step to sign-in flows.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('84902cee-488e-4583-aad3-f2fbf318cb9e', $q$Enterprise SSO, SAML, and OIDC$q$, $q$Enterprise identity protocols available on all paid tiers, not restricted to top-tier plans.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('84902cee-488e-4583-aad3-f2fbf318cb9e', $q$Organizations and multi-tenancy$q$, $q$Native support for teams, roles, and multi-tenant account structures for B2B SaaS applications.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('84902cee-488e-4583-aad3-f2fbf318cb9e', $q$Framework SDKs and APIs$q$, $q$SDKs for React, Next.js, Remix, and other frameworks, plus lower-level APIs for fully custom auth UIs.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('84902cee-488e-4583-aad3-f2fbf318cb9e', $q$Session management$q$, $q$Configurable session lifetimes and secure session handling across web and mobile clients.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('84902cee-488e-4583-aad3-f2fbf318cb9e', $q$Compliance and audit features$q$, $q$SOC 2 reporting, HIPAA/BAA support, and SIEM integration available on Business and Enterprise plans.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('84902cee-488e-4583-aad3-f2fbf318cb9e', $q$Free Hobby tier supports up to 50,000 monthly retained users with no credit card$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('84902cee-488e-4583-aad3-f2fbf318cb9e', $q$Enterprise SSO/SAML/OIDC included on all paid tiers, not gated to Enterprise only$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('84902cee-488e-4583-aad3-f2fbf318cb9e', $q$Strong developer experience with prebuilt UI components and deep React/Next.js support$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('84902cee-488e-4583-aad3-f2fbf318cb9e', $q$Native multi-tenant organizations feature simplifies B2B SaaS account structures$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('84902cee-488e-4583-aad3-f2fbf318cb9e', $q$MRU-based pricing can become expensive at scale compared to flat-rate competitors$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('84902cee-488e-4583-aad3-f2fbf318cb9e', $q$Dashboard seat limits on lower tiers may require upgrading for larger teams$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('84902cee-488e-4583-aad3-f2fbf318cb9e', $q$Some enterprise-grade add-ons (custom session lifetime, SSO connections) cost extra even on Pro$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('84902cee-488e-4583-aad3-f2fbf318cb9e', $q$Business and Enterprise plans represent a large price jump from Pro ($25 to $300+/month)$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('84902cee-488e-4583-aad3-f2fbf318cb9e', $q$Is Clerk free to use?$q$, $q$Yes. Clerk's Hobby plan is free and includes up to 50,000 Monthly Retained Users (MRUs) per application, unlimited applications, and up to three dashboard seats.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('84902cee-488e-4583-aad3-f2fbf318cb9e', $q$What is a Monthly Retained User (MRU) in Clerk's pricing?$q$, $q$An MRU is a user who returns to the application more than 24 hours after signing up, similar to but stricter than a typical Monthly Active User (MAU) metric used by other platforms.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('84902cee-488e-4583-aad3-f2fbf318cb9e', $q$Does Clerk support enterprise SSO and SAML?$q$, $q$Yes, and unlike many competitors, Clerk includes SAML, OIDC, and enterprise SSO on all of its paid tiers rather than only its most expensive Enterprise plan.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('84902cee-488e-4583-aad3-f2fbf318cb9e', $q$What frameworks does Clerk support?$q$, $q$Clerk provides SDKs for React, Next.js, Remix, and other modern web frameworks, along with APIs for custom integrations.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('84902cee-488e-4583-aad3-f2fbf318cb9e', $q$How much does Clerk cost at scale?$q$, $q$Beyond the included 50,000 MRUs on the Pro plan, additional users are billed at $0.02 per MRU. The Business plan costs $300/month ($250/month annually) with volume pricing on overages, and Enterprise is custom-priced.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('84902cee-488e-4583-aad3-f2fbf318cb9e', $q$Who is Clerk best suited for?$q$, $q$Clerk is best suited for startups and product teams building modern web applications, particularly React-based apps, that want production-ready authentication without building it in-house.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('84902cee-488e-4583-aad3-f2fbf318cb9e', $q$Adding authentication to a new web app$q$, $q$Startups drop in Clerk's prebuilt sign-up and sign-in components to launch with production-grade auth in hours instead of building it from scratch.$q$, $q$Early-stage startups and indie developers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('84902cee-488e-4583-aad3-f2fbf318cb9e', $q$B2B SaaS multi-tenant account management$q$, $q$Product teams use Clerk's Organizations feature to manage teams, roles, and permissions within a multi-tenant B2B application.$q$, $q$B2B SaaS engineering teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('84902cee-488e-4583-aad3-f2fbf318cb9e', $q$Enterprise SSO for regulated applications$q$, $q$Companies serving enterprise customers use Clerk's SAML/SSO support to meet customer identity requirements without switching identity providers.$q$, $q$Mid-market and enterprise software vendors$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('84902cee-488e-4583-aad3-f2fbf318cb9e', $q$Hobby$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Up to 50,000 MRUs per app","Unlimited applications","Up to 3 dashboard seats","Core auth features"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('84902cee-488e-4583-aad3-f2fbf318cb9e', $q$Pro$q$, $q$$25/month ($20/month annually)$q$, $q$monthly or annual$q$, NULL, $q$["50,000 MRUs included, $0.02/MRU after","Branding removal","Multi-factor authentication","Enterprise SSO connections available as $75/mo add-on"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('84902cee-488e-4583-aad3-f2fbf318cb9e', $q$Business$q$, $q$$300/month ($250/month annually)$q$, $q$monthly or annual$q$, NULL, $q$["10 dashboard seats","SOC 2 report","Priority support","30-day application log retention"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('84902cee-488e-4583-aad3-f2fbf318cb9e', $q$Enterprise$q$, $q$Custom$q$, $q$annual$q$, NULL, $q$["99.99% uptime SLA","HIPAA compliance with BAA","Custom log retention","SIEM integration"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('84902cee-488e-4583-aad3-f2fbf318cb9e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Clerk was founded in 2019 by twin brothers Braden Sidoti and Colin Sidoti in San Francisco to give application developers a faster path to production-ready authentication than building it themselves or integrating a heavier legacy identity platform. The product combines prebuilt, customizable UI components with backend user-management infrastructure, so teams can add sign-up, sign-in, profile management, and organizations to an app without owning the underlying security logic.$q$, $q$Clerk has grown to support most major web frameworks, with especially deep integration for React-based stacks like Next.js and Remix, and now serves startups through large engineering teams that need enterprise identity features such as SAML and SSO without switching to a dedicated identity provider.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('84902cee-488e-4583-aad3-f2fbf318cb9e', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Clerk ships drop-in UI components for sign-up, sign-in, user profile, and organization management that can be styled to match an application's design, along with lower-level SDKs and APIs for teams that want to build fully custom interfaces on top of Clerk's auth backend. It supports multi-factor authentication, social login providers, and passkeys alongside traditional email/password flows.$q$, $q$Enterprise identity protocols, SAML, OIDC, and SSO, are included on every paid tier rather than reserved for the top plan, and Clerk supports multi-tenant "organizations" out of the box for B2B SaaS applications that need to manage teams and roles within a single account structure.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('84902cee-488e-4583-aad3-f2fbf318cb9e', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Clerk's Hobby plan is free and includes up to 50,000 Monthly Retained Users (MRUs) per application, unlimited applications, and up to three dashboard seats. The Pro plan is $25/month ($20/month billed annually), includes the same 50,000 MRU allotment with overages at $0.02 per additional MRU, and adds branding removal and MFA; enterprise SSO connections and custom session lifetime are available as $75/month add-ons.$q$, $q$The Business plan is $300/month ($250/month billed annually) and adds a SOC 2 report, priority support, 30-day log retention, and ten dashboard seats. Enterprise pricing is custom and adds a 99.99% uptime SLA, HIPAA/BAA support, custom log retention, and SIEM integration.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('84902cee-488e-4583-aad3-f2fbf318cb9e', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('84902cee-488e-4583-aad3-f2fbf318cb9e', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('84902cee-488e-4583-aad3-f2fbf318cb9e', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('84902cee-488e-4583-aad3-f2fbf318cb9e', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('040862c3-0d04-4dd4-af23-2164939cfd29', $q$Git-push deployment$q$, $q$Deploy applications by pushing to a git repository; the platform builds and runs the app automatically.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('040862c3-0d04-4dd4-af23-2164939cfd29', $q$Automatic scaling$q$, $q$Compute resources scale up or down based on load, with a customer-set maximum price ceiling to control costs.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('040862c3-0d04-4dd4-af23-2164939cfd29', $q$Fully managed databases$q$, $q$Managed database services run alongside application compute on the same platform.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('040862c3-0d04-4dd4-af23-2164939cfd29', $q$Broad language and framework support$q$, $q$Supports more than 25 programming languages and frameworks out of the box.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('040862c3-0d04-4dd4-af23-2164939cfd29', $q$European, GDPR-compliant infrastructure$q$, $q$All data processing occurs on infrastructure located in France, supporting EU data residency requirements.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('040862c3-0d04-4dd4-af23-2164939cfd29', $q$Per-second usage billing$q$, $q$Costs are metered by the second based on actual resource consumption rather than flat monthly tiers.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('040862c3-0d04-4dd4-af23-2164939cfd29', $q$Free trial credits$q$, $q$New signups receive complimentary credits to test the platform without providing payment details.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('040862c3-0d04-4dd4-af23-2164939cfd29', $q$European, GDPR-compliant infrastructure with data centers in France$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('040862c3-0d04-4dd4-af23-2164939cfd29', $q$Simple git-push deployment with automatic scaling and maintenance$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('040862c3-0d04-4dd4-af23-2164939cfd29', $q$Fully managed databases alongside compute on one platform$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('040862c3-0d04-4dd4-af23-2164939cfd29', $q$Per-second usage billing can reduce costs versus over-provisioned fixed plans$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('040862c3-0d04-4dd4-af23-2164939cfd29', $q$Free trial credits available without requiring a payment card$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('040862c3-0d04-4dd4-af23-2164939cfd29', $q$No permanent free tier for production workloads$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('040862c3-0d04-4dd4-af23-2164939cfd29', $q$Usage-based billing can produce unpredictable bills during traffic spikes without a spending cap set$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('040862c3-0d04-4dd4-af23-2164939cfd29', $q$No flat published starting price, since cost depends on selected resources$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('040862c3-0d04-4dd4-af23-2164939cfd29', $q$Smaller ecosystem and community compared to larger US-based PaaS competitors$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('040862c3-0d04-4dd4-af23-2164939cfd29', $q$What is Clever Cloud?$q$, $q$Clever Cloud is a French Platform-as-a-Service that lets developers deploy applications with a git push while the platform automatically handles scaling, monitoring, and infrastructure maintenance, running entirely on European data centers.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('040862c3-0d04-4dd4-af23-2164939cfd29', $q$How does Clever Cloud pricing work?$q$, $q$Clever Cloud bills by the second based on actual resource usage rather than fixed monthly plans. Customers fund an account balance reflecting expected usage and can set a maximum spending ceiling to control costs during scaling.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('040862c3-0d04-4dd4-af23-2164939cfd29', $q$Does Clever Cloud have a free tier?$q$, $q$There is no permanent free production tier, but new accounts receive free trial credits to test the platform without entering a payment card.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('040862c3-0d04-4dd4-af23-2164939cfd29', $q$Is Clever Cloud GDPR compliant?$q$, $q$Yes. Clever Cloud operates exclusively on infrastructure located in France and the EU, and the company states it is fully GDPR compliant.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('040862c3-0d04-4dd4-af23-2164939cfd29', $q$What languages and frameworks does Clever Cloud support?$q$, $q$Clever Cloud supports more than 25 programming languages and frameworks, along with fully managed database services alongside application compute.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('040862c3-0d04-4dd4-af23-2164939cfd29', $q$Who should use Clever Cloud instead of AWS or Heroku?$q$, $q$Clever Cloud is a strong fit for teams that need EU-only data residency and prefer simple, automatic deployment and scaling over managing raw cloud infrastructure or Kubernetes themselves.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('040862c3-0d04-4dd4-af23-2164939cfd29', $q$EU data-sovereign application hosting$q$, $q$Companies that must keep application and database infrastructure within EU borders for regulatory reasons deploy on Clever Cloud's French data centers.$q$, $q$European companies with GDPR or data residency requirements$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('040862c3-0d04-4dd4-af23-2164939cfd29', $q$Simplified deployment for small engineering teams$q$, $q$Teams without dedicated DevOps resources use git-push deployment and automatic scaling to avoid managing servers or Kubernetes directly.$q$, $q$Small-to-mid-size engineering teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('040862c3-0d04-4dd4-af23-2164939cfd29', $q$Managed application plus database hosting$q$, $q$Startups run both their application compute and managed databases on a single platform instead of stitching together separate hosting and database vendors.$q$, $q$Startups and growing SaaS companies$q$, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('040862c3-0d04-4dd4-af23-2164939cfd29', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Clever Cloud was founded in 2010 in Nantes, France, with a focus on building a European alternative to US-based PaaS and cloud providers. The company operates its infrastructure entirely within EU borders, with data centers in France, and positions GDPR compliance and data sovereignty as core parts of its value proposition rather than an add-on.$q$, $q$The platform's core workflow is deploy-by-git-push: developers push code and Clever Cloud handles builds, scaling, monitoring, and infrastructure maintenance automatically, supporting more than 25 languages and frameworks alongside fully managed database services.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('040862c3-0d04-4dd4-af23-2164939cfd29', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Applications deploy via a standard git push, with the platform building and running the app without requiring developers to write Dockerfiles or manage container orchestration directly. Compute resources auto-scale based on load, and customers can set a maximum price they're willing to incur so scaling doesn't produce unpredictable bills.$q$, $q$Clever Cloud offers fully managed databases (relational and other engines) alongside compute, so a team can run its entire application and data layer on the same platform. All infrastructure runs on European data centers, supporting organizations that need to keep data processing within the EU for regulatory or contractual reasons.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('040862c3-0d04-4dd4-af23-2164939cfd29', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Clever Cloud bills by the second based on actual resource consumption rather than offering fixed monthly plan tiers. Customers fund their account with a balance that reflects expected usage, and that amount is adjusted month to month based on real consumption, with an interactive calculator on the pricing page for estimating costs by product and region.$q$, $q$New accounts receive free credits to test the platform without a payment card. There is no permanent free production tier, and because billing follows usage, traffic spikes can increase costs unless a spending ceiling is configured; startup and enterprise programs with custom pricing are available by contacting sales.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('040862c3-0d04-4dd4-af23-2164939cfd29', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('040862c3-0d04-4dd4-af23-2164939cfd29', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('844e3580-b2a6-44af-ab86-815377448e1a', $q$Drag-and-drop funnel builder$q$, $q$Visually build landing pages, sales pages, and checkout flows and chain them into a complete marketing funnel without code.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('844e3580-b2a6-44af-ab86-815377448e1a', $q$Email and SMS marketing automation$q$, $q$Built-in automation for follow-up sequences, broadcasts, and triggered messages without a separate ESP.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('844e3580-b2a6-44af-ab86-815377448e1a', $q$Course and membership hosting$q$, $q$Host and sell online courses and membership content directly within the platform.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('844e3580-b2a6-44af-ab86-815377448e1a', $q$Affiliate program management$q$, $q$Run a referral or affiliate partner program with tracking and payouts built into ClickFunnels.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('844e3580-b2a6-44af-ab86-815377448e1a', $q$Built-in CRM$q$, $q$Track contacts, pipeline stages, and customer interactions without a separate CRM tool.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('844e3580-b2a6-44af-ab86-815377448e1a', $q$AI copywriting assistance$q$, $q$Generate marketing copy using an included AI word allotment that scales with plan tier.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('844e3580-b2a6-44af-ab86-815377448e1a', $q$Custom code editor and API access$q$, $q$Available on Scale and higher tiers for teams that want to extend or customize beyond the no-code builder.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('844e3580-b2a6-44af-ab86-815377448e1a', $q$Funnel and page templates$q$, $q$A library of pre-built funnel and page templates based on Russell Brunson's funnel-marketing frameworks.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('844e3580-b2a6-44af-ab86-815377448e1a', $q$All-in-one platform replaces separate page builder, email tool, course host, and CRM$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('844e3580-b2a6-44af-ab86-815377448e1a', $q$No-code funnel builder is accessible to non-technical entrepreneurs$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('844e3580-b2a6-44af-ab86-815377448e1a', $q$Large library of templates and training content built around a proven funnel methodology$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('844e3580-b2a6-44af-ab86-815377448e1a', $q$Unlimited funnels and visitors included on every plan$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('844e3580-b2a6-44af-ab86-815377448e1a', $q$14-day free trial available on all monthly plans$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('844e3580-b2a6-44af-ab86-815377448e1a', $q$Starting price of $97/month is higher than many standalone landing-page builders$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('844e3580-b2a6-44af-ab86-815377448e1a', $q$API access and custom code editing are limited to Scale and higher tiers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('844e3580-b2a6-44af-ab86-815377448e1a', $q$Contact and email-send limits can require an upgrade as a list grows$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('844e3580-b2a6-44af-ab86-815377448e1a', $q$Less suited to complex e-commerce catalogs than dedicated e-commerce platforms$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('844e3580-b2a6-44af-ab86-815377448e1a', $q$What is ClickFunnels used for?$q$, $q$ClickFunnels is used to build sales funnels, combining landing pages, checkout flows, upsells, email/SMS follow-up, and course or membership delivery, without needing to code or assemble separate tools.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('844e3580-b2a6-44af-ab86-815377448e1a', $q$How much does ClickFunnels cost?$q$, $q$ClickFunnels starts at $97/month for the Launch plan, with Scale at $197/month and Optimize at $297/month. An annual-only Dominate plan costs $5,997/year. All monthly plans include a 14-day free trial.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('844e3580-b2a6-44af-ab86-815377448e1a', $q$Who founded ClickFunnels?$q$, $q$ClickFunnels was founded in October 2014 by Russell Brunson and Todd Dickerson, launched without venture capital funding under their entity Etison LLC.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('844e3580-b2a6-44af-ab86-815377448e1a', $q$Does ClickFunnels include email marketing?$q$, $q$Yes, built-in email and SMS marketing automation is included on all plans, with sending limits that increase at higher tiers.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('844e3580-b2a6-44af-ab86-815377448e1a', $q$Can I sell online courses on ClickFunnels?$q$, $q$Yes, ClickFunnels includes course and membership site hosting, with the number of courses allowed increasing by plan tier.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('844e3580-b2a6-44af-ab86-815377448e1a', $q$What are alternatives to ClickFunnels?$q$, $q$Common alternatives include Kartra, Kajabi, GoHighLevel, and landing-page-focused tools like Leadpages, depending on whether a business needs full funnel/CRM functionality or just page building.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('844e3580-b2a6-44af-ab86-815377448e1a', $q$Digital product and course launches$q$, $q$Creators and coaches build a complete funnel, from opt-in page to checkout to course delivery, to launch and sell digital products.$q$, $q$Course creators and coaches$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('844e3580-b2a6-44af-ab86-815377448e1a', $q$Lead generation funnels for local or service businesses$q$, $q$Service businesses build opt-in and appointment-booking funnels connected to automated email/SMS follow-up sequences.$q$, $q$Local businesses and service providers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('844e3580-b2a6-44af-ab86-815377448e1a', $q$Affiliate-driven marketing campaigns$q$, $q$Marketers run funnels with an integrated affiliate program to recruit partners who promote products for a commission.$q$, $q$Entrepreneurs running affiliate or partner marketing programs$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('844e3580-b2a6-44af-ab86-815377448e1a', $q$Launch$q$, $q$$97/month$q$, $q$monthly$q$, NULL, $q$["1 workspace, 2 team members","10K contacts, 50K emails/month","3 courses, 5 custom domains","Standard support, 1M AI words"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('844e3580-b2a6-44af-ab86-815377448e1a', $q$Scale$q$, $q$$197/month$q$, $q$monthly$q$, NULL, $q$["5 workspaces, 5 team members","75K contacts, 300K emails/month","6 courses, unlimited custom domains","Custom code editor, API access, 2M AI words"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('844e3580-b2a6-44af-ab86-815377448e1a', $q$Optimize$q$, $q$$297/month$q$, $q$monthly$q$, NULL, $q$["10 workspaces, 10 team members","150K contacts, 750K emails/month","10 courses, unlimited custom domains","Custom code editor, API access, 5M AI words"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('844e3580-b2a6-44af-ab86-815377448e1a', $q$Dominate$q$, $q$$5,997/year$q$, $q$annual$q$, NULL, $q$["20 workspaces, 20 team members","400K contacts, 1.2M emails/month","20 courses, VIP support","Custom code editor, API access, 10M AI words"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('844e3580-b2a6-44af-ab86-815377448e1a', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$ClickFunnels launched in October 2014, built by Russell Brunson and Todd Dickerson to let marketers and entrepreneurs assemble complete sales funnels, landing pages, order forms, upsells, and follow-up sequences, without needing a developer or a separate stack of tools. The company grew primarily through Brunson's own marketing audience and bootstrapped its growth without outside venture funding, becoming one of the fastest-growing privately held SaaS companies in North America by the late 2010s.$q$, $q$The current version of the platform, ClickFunnels 2.0, consolidates page building, email/SMS automation, course and membership hosting, affiliate management, and CRM functionality into one product, aiming to replace the need for a marketer to combine a page builder, an email tool, a course platform, and a CRM separately.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('844e3580-b2a6-44af-ab86-815377448e1a', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Users build funnels visually with a drag-and-drop editor, choosing from templates for opt-in pages, sales pages, checkout flows, and upsell sequences, then connect them into a complete customer journey. Built-in email and SMS marketing automation lets teams follow up with leads and customers without a separate email service provider.$q$, $q$The platform also includes course and membership site hosting for creators selling digital products, an affiliate program manager for running a referral partner program, and, on higher tiers, a custom code editor and API access for teams that want to extend the platform beyond its no-code building blocks.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('844e3580-b2a6-44af-ab86-815377448e1a', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$ClickFunnels offers three monthly plans: Launch at $97/month (1 workspace, 10K contacts, 3 courses), Scale at $197/month (5 workspaces, 75K contacts, API access), and Optimize at $297/month (10 workspaces, 150K contacts). An annual-only Dominate plan costs $5,997/year with 20 workspaces, 400K contacts, and VIP support with private onboarding.$q$, $q$All monthly plans include unlimited funnels and unlimited visitors, and every plan comes with a 14-day free trial. Higher tiers include larger allotments of built-in AI-generated words for on-platform copywriting assistance, along with priority or live-chat support.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('844e3580-b2a6-44af-ab86-815377448e1a', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
