INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f0712a2a-3c5e-47ea-8501-6e6e45003e44', $q$Single-source content publishing$q$, $q$Write content once and reuse it across multiple output formats and product versions, reducing duplicate maintenance.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f0712a2a-3c5e-47ea-8501-6e6e45003e44', $q$Multi-version documentation management$q$, $q$Maintain documentation for several product releases in parallel within the same project.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f0712a2a-3c5e-47ea-8501-6e6e45003e44', $q$API documentation support$q$, $q$Author and publish API reference documentation alongside standard user manuals.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f0712a2a-3c5e-47ea-8501-6e6e45003e44', $q$Translation and localization management$q$, $q$Manage multilingual documentation workflows for teams publishing docs in multiple languages.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f0712a2a-3c5e-47ea-8501-6e6e45003e44', $q$Context-sensitive help configuration$q$, $q$Embed documentation directly inside a software product's UI, tied to specific screens or features.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f0712a2a-3c5e-47ea-8501-6e6e45003e44', $q$In-depth analytics$q$, $q$Track how readers use published documentation to identify gaps or high-traffic content.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f0712a2a-3c5e-47ea-8501-6e6e45003e44', $q$Content migration tools$q$, $q$Import existing documentation from Word, HTML, CHM, and OpenOffice into ClickHelp.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f0712a2a-3c5e-47ea-8501-6e6e45003e44', $q$Custom branding$q$, $q$Apply custom CSS and UI templates so published docs match a company's brand.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f0712a2a-3c5e-47ea-8501-6e6e45003e44', $q$Fully cloud-based, letting distributed writing teams collaborate without desktop software$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f0712a2a-3c5e-47ea-8501-6e6e45003e44', $q$Strong single-sourcing and multi-version documentation support$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f0712a2a-3c5e-47ea-8501-6e6e45003e44', $q$Enterprise security standard across tiers (SOC 2 Type II, GDPR/CCPA, AES-256)$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f0712a2a-3c5e-47ea-8501-6e6e45003e44', $q$Built-in translation and localization management for multilingual docs$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f0712a2a-3c5e-47ea-8501-6e6e45003e44', $q$Starting price of $185/month is higher than several documentation tool competitors$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f0712a2a-3c5e-47ea-8501-6e6e45003e44', $q$Smaller company and team size relative to larger documentation platform vendors$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f0712a2a-3c5e-47ea-8501-6e6e45003e44', $q$Full feature set (translation workflows, deep analytics) concentrated in higher tiers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f0712a2a-3c5e-47ea-8501-6e6e45003e44', $q$Less brand recognition than desktop-authoring incumbents like MadCap Flare$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f0712a2a-3c5e-47ea-8501-6e6e45003e44', $q$What is ClickHelp used for?$q$, $q$ClickHelp is used to create, host, and publish technical documentation, including user manuals, API references, and knowledge bases, entirely from a browser-based platform.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f0712a2a-3c5e-47ea-8501-6e6e45003e44', $q$How much does ClickHelp cost?$q$, $q$ClickHelp's plans start at $185/month for Starter, $310/month for Growth, and $610/month for Professional, excluding tax.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f0712a2a-3c5e-47ea-8501-6e6e45003e44', $q$Does ClickHelp support multiple languages?$q$, $q$Yes, ClickHelp includes translation and localization management features for teams publishing documentation in multiple languages.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f0712a2a-3c5e-47ea-8501-6e6e45003e44', $q$What is single-sourcing in ClickHelp?$q$, $q$Single-sourcing means writing content once and reusing it across multiple output formats (web help, PDF, CHM) and multiple product versions, instead of maintaining separate copies of the same content.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f0712a2a-3c5e-47ea-8501-6e6e45003e44', $q$Can I migrate existing documentation into ClickHelp?$q$, $q$Yes, ClickHelp provides content migration tools that import documentation from Word, HTML, CHM, and OpenOffice formats.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f0712a2a-3c5e-47ea-8501-6e6e45003e44', $q$Who uses ClickHelp?$q$, $q$ClickHelp is used by software vendors and technical writing teams, including enterprise clients like IBM, to manage documentation across multiple product versions and languages.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f0712a2a-3c5e-47ea-8501-6e6e45003e44', $q$Multi-version product documentation$q$, $q$Software vendors maintain documentation for several concurrently supported product versions using single-source publishing.$q$, $q$Technical writing teams at software companies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f0712a2a-3c5e-47ea-8501-6e6e45003e44', $q$Embedded, context-sensitive help$q$, $q$Product teams embed ClickHelp-hosted documentation directly inside their application UI, tied to specific screens.$q$, $q$Product and UX teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f0712a2a-3c5e-47ea-8501-6e6e45003e44', $q$Multilingual documentation programs$q$, $q$Global software companies manage translation workflows to publish the same documentation set in multiple languages.$q$, $q$Localization and documentation teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f0712a2a-3c5e-47ea-8501-6e6e45003e44', $q$Starter$q$, $q$$185/month$q$, $q$monthly$q$, NULL, $q$["Core authoring and publishing","Single-source publishing","Basic analytics"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f0712a2a-3c5e-47ea-8501-6e6e45003e44', $q$Growth$q$, $q$$310/month$q$, $q$monthly$q$, NULL, $q$["Everything in Starter","Additional author seats and storage","Expanded analytics"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f0712a2a-3c5e-47ea-8501-6e6e45003e44', $q$Professional$q$, $q$$610/month$q$, $q$monthly$q$, NULL, $q$["Everything in Growth","Translation and localization workflows","Advanced enterprise features"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f0712a2a-3c5e-47ea-8501-6e6e45003e44', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$ClickHelp was founded in 2010 in Yerevan, Armenia, to give technical writing teams a fully cloud-based alternative to desktop documentation authoring tools, letting distributed teams write, review, and publish documentation collaboratively from a browser rather than syncing files between local installations.$q$, $q$The platform is used by software vendors and product teams to produce user manuals, API references, and knowledge bases, with a particular emphasis on single-sourcing: writing content once and reusing it across multiple product versions and output formats rather than maintaining separate copies.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f0712a2a-3c5e-47ea-8501-6e6e45003e44', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Single-source publishing lets teams maintain one set of content and generate multiple outputs, web help, PDF, and CHM, from it, while multi-version documentation management keeps docs for several product releases organized in parallel. Built-in translation management supports localization workflows for teams publishing documentation in multiple languages.$q$, $q$ClickHelp also includes API documentation support, in-depth analytics on reader behavior within published docs, context-sensitive help configuration for embedding documentation inside a software product, and content migration tools that import existing docs from Word, HTML, CHM, and OpenOffice.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f0712a2a-3c5e-47ea-8501-6e6e45003e44', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$ClickHelp is sold as a monthly subscription with three tiers: Starter at $185/month, Growth at $310/month, and Professional at $610/month (all prices exclude tax). Higher tiers increase author seats, storage, and access to advanced features like deeper analytics and translation workflows.$q$, $q$The platform includes enterprise-grade security as standard, SOC 2 Type II certification, GDPR/CCPA compliance, AES-256 encryption, and a 99.9% uptime SLA with daily automatic backups, across its paid tiers.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f0712a2a-3c5e-47ea-8501-6e6e45003e44', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f0712a2a-3c5e-47ea-8501-6e6e45003e44', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d1cc98c8-156a-4960-9e1b-8d537e303a0e', $q$Column-oriented storage engine$q$, $q$Optimized for analytical queries over large datasets, with high compression and fast aggregate scans.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d1cc98c8-156a-4960-9e1b-8d537e303a0e', $q$Real-time query performance$q$, $q$Designed to return results over billions of rows with low latency for dashboards and reporting.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d1cc98c8-156a-4960-9e1b-8d537e303a0e', $q$Distributed, sharded architecture$q$, $q$Scales horizontally across nodes for very large datasets and high query concurrency.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d1cc98c8-156a-4960-9e1b-8d537e303a0e', $q$Standard SQL support$q$, $q$Query with familiar SQL syntax plus extensions for time-series and analytical functions.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d1cc98c8-156a-4960-9e1b-8d537e303a0e', $q$Self-hosted deployment$q$, $q$Run the open-source database on any infrastructure with no licensing cost.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d1cc98c8-156a-4960-9e1b-8d537e303a0e', $q$ClickHouse Cloud (serverless managed service)$q$, $q$Fully managed, auto-scaling version of the database with separate compute and storage billing.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d1cc98c8-156a-4960-9e1b-8d537e303a0e', $q$High availability and automated backups$q$, $q$Available on ClickHouse Cloud without requiring manual cluster operations.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d1cc98c8-156a-4960-9e1b-8d537e303a0e', $q$Enterprise compliance features$q$, $q$HIPAA/PCI support, SAML/SSO, and customer-managed encryption keys on the Enterprise Cloud tier.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d1cc98c8-156a-4960-9e1b-8d537e303a0e', $q$Core database is free, open source, and can be self-hosted with no licensing cost$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d1cc98c8-156a-4960-9e1b-8d537e303a0e', $q$Very strong performance for analytical queries over large datasets$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d1cc98c8-156a-4960-9e1b-8d537e303a0e', $q$Proven at scale by companies including Uber, Comcast, and Cisco$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d1cc98c8-156a-4960-9e1b-8d537e303a0e', $q$ClickHouse Cloud removes operational burden of running clusters manually$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d1cc98c8-156a-4960-9e1b-8d537e303a0e', $q$30-day trial with $300 in credit for evaluating ClickHouse Cloud$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d1cc98c8-156a-4960-9e1b-8d537e303a0e', $q$Not designed for transactional (OLTP) workloads; row-oriented databases are a better fit for those$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d1cc98c8-156a-4960-9e1b-8d537e303a0e', $q$Self-hosting at scale requires real operational expertise to manage clusters and storage$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d1cc98c8-156a-4960-9e1b-8d537e303a0e', $q$ClickHouse Cloud costs can rise quickly for production workloads on the Scale and Enterprise tiers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d1cc98c8-156a-4960-9e1b-8d537e303a0e', $q$Separate compute and storage billing on Cloud can make cost estimation less straightforward than flat pricing$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d1cc98c8-156a-4960-9e1b-8d537e303a0e', $q$Is ClickHouse free?$q$, $q$The core ClickHouse database is free and open source and can be self-hosted on any infrastructure with no licensing cost. ClickHouse Cloud, the managed serverless offering, is billed separately for compute and storage.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d1cc98c8-156a-4960-9e1b-8d537e303a0e', $q$What is ClickHouse used for?$q$, $q$ClickHouse is used for real-time analytics, observability, and reporting workloads that require running SQL queries over very large datasets with low latency, such as web analytics, log analysis, and business intelligence dashboards.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d1cc98c8-156a-4960-9e1b-8d537e303a0e', $q$How much does ClickHouse Cloud cost?$q$, $q$ClickHouse Cloud pricing separates compute (roughly $0.22-$0.39 per compute unit-hour depending on tier) and storage (about $25/TB-month flat). The Basic tier can run in the range of $66-190/month depending on usage, the Scale tier starts around $499/month, and Enterprise pricing depends on configuration.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d1cc98c8-156a-4960-9e1b-8d537e303a0e', $q$Who founded ClickHouse and when?$q$, $q$The technology originated in 2009 when Alexey Milovidov and collaborators began building it to power Yandex.Metrica; it was open-sourced in 2016, and ClickHouse Inc. was incorporated in San Francisco in September 2021 to commercialize it.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d1cc98c8-156a-4960-9e1b-8d537e303a0e', $q$Is ClickHouse good for transactional (OLTP) applications?$q$, $q$No. ClickHouse is optimized for analytical (OLAP) workloads over large datasets, not for typical transactional application databases; row-oriented databases like PostgreSQL are generally a better fit for OLTP use cases.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d1cc98c8-156a-4960-9e1b-8d537e303a0e', $q$What companies use ClickHouse?$q$, $q$Companies including Uber, Comcast, eBay, and Cisco use ClickHouse for high-volume analytics, observability, and reporting workloads.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d1cc98c8-156a-4960-9e1b-8d537e303a0e', $q$Real-time observability and log analytics$q$, $q$Engineering teams query billions of log and metric events with low latency to power observability dashboards.$q$, $q$Platform and SRE engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d1cc98c8-156a-4960-9e1b-8d537e303a0e', $q$Product and web analytics at scale$q$, $q$Companies run large-scale clickstream and product-usage analytics, similar to ClickHouse's original use powering Yandex.Metrica.$q$, $q$Data engineering and analytics teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d1cc98c8-156a-4960-9e1b-8d537e303a0e', $q$Customer-facing analytics dashboards$q$, $q$SaaS companies embed ClickHouse-backed dashboards to give customers real-time analytics within their own product.$q$, $q$SaaS product and data teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d1cc98c8-156a-4960-9e1b-8d537e303a0e', $q$Self-hosted (open source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["No licensing cost","Full database feature set","Requires self-managed infrastructure"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d1cc98c8-156a-4960-9e1b-8d537e303a0e', $q$ClickHouse Cloud - Basic$q$, $q$From ~$66/month (usage-based)$q$, $q$usage-based$q$, NULL, $q$["Serverless managed deployment","Suited for experimentation and small workloads","Compute billed per minute, storage per TB-month"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d1cc98c8-156a-4960-9e1b-8d537e303a0e', $q$ClickHouse Cloud - Scale$q$, $q$From ~$499/month (usage-based)$q$, $q$usage-based$q$, NULL, $q$["Production workloads","Replica and shard scaling","Higher availability guarantees"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d1cc98c8-156a-4960-9e1b-8d537e303a0e', $q$ClickHouse Cloud - Enterprise$q$, $q$Custom (usage-based)$q$, $q$usage-based$q$, NULL, $q$["HIPAA/PCI compliance support","SAML/SSO","Customer-managed encryption keys (CMEK)"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d1cc98c8-156a-4960-9e1b-8d537e303a0e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$ClickHouse's technology traces back to 2009, when Alexey Milovidov and collaborators began building it to power Yandex.Metrica's web analytics at massive scale; it first went into production in 2012 and was released as open source in 2016. ClickHouse Inc. was incorporated in San Francisco in September 2021 to commercialize the open-source database, with a European subsidiary, ClickHouse B.V., based in Amsterdam.$q$, $q$The database is a column-oriented OLAP system, optimized for running analytical SQL queries over very large datasets with low latency, and has been adopted by companies including Uber, Comcast, eBay, and Cisco for observability, product analytics, and real-time reporting workloads.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d1cc98c8-156a-4960-9e1b-8d537e303a0e', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$ClickHouse's columnar storage engine is built specifically for read-heavy analytical queries over billions of rows, supporting standard SQL along with extensions for time-series and analytical functions. It supports high compression ratios, real-time data ingestion, and distributed, sharded deployments for horizontal scale.$q$, $q$The self-hosted, open-source edition can be deployed on any infrastructure with no licensing cost, while ClickHouse Cloud, the company's managed offering, adds serverless auto-scaling, automated backups, and built-in high availability without requiring a team to operate the underlying cluster themselves.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d1cc98c8-156a-4960-9e1b-8d537e303a0e', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The core ClickHouse database is free and open source for self-hosted use, with no licensing fees regardless of scale. ClickHouse Cloud, the managed serverless offering, separates billing into compute (metered per minute, roughly $0.22-$0.39 per compute unit-hour depending on tier) and storage (a flat rate of about $25 per terabyte-month across all tiers).$q$, $q$ClickHouse Cloud has three tiers: Basic for experimentation and small workloads, Scale starting around $499/month for production workloads needing replica and shard scaling, and Enterprise for organizations needing compliance features like HIPAA/PCI support, SAML/SSO, and customer-managed encryption keys. New accounts get a 30-day trial with $300 in credit before choosing a paid plan or self-hosting.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d1cc98c8-156a-4960-9e1b-8d537e303a0e', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
