-- ── Clerk ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Clerk is a developer-focused authentication and user management platform offering prebuilt sign-in flows, UI components, and enterprise SSO for modern web apps.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2019, founded_year),
  company_size = COALESCE($q$~200 employees$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Clerk Review: Authentication & User Management Pricing$q$, seo_title),
  seo_meta_description = COALESCE($q$Clerk provides prebuilt auth, user management, and SSO for developers. Compare pricing plans, MAU limits, features, pros, cons, and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Clerk is a developer-focused authentication and user management platform founded in 2019 by twin brothers Braden Sidoti and Colin Sidoti, headquartered in San Francisco, California. It provides prebuilt, customizable UI components and backend infrastructure for sign-up, sign-in, user profile management, organizations/multi-tenancy, and session handling, aimed at letting engineering teams add production-grade authentication to a web or mobile app in hours rather than building it from scratch. Clerk supports modern frameworks including Next.js, React, Remix, and others, and exposes both drop-in UI components and lower-level APIs and SDKs for teams that want full control over the interface. Core authentication protocols, including SAML, OIDC, and enterprise SSO, are available across all pricing tiers rather than gated to the most expensive plan, which differentiates Clerk from some competitors that reserve enterprise identity protocols for top-tier contracts. Clerk's pricing is usage-based on Monthly Retained Users (MRU), a metric similar to MAU but that only counts users who return more than 24 hours after signup. The Hobby plan is free and includes up to 50,000 MRUs per app, unlimited applications, and up to three dashboard seats, making it usable for side projects and early-stage startups without a credit card. The Pro plan costs $25/month ($20/month billed annually) and includes 50,000 MRUs with additional users billed at $0.02 per MRU beyond that, plus branding removal and multi-factor authentication; optional add-ons like custom session lifetime and enterprise SSO connections cost $75/month each on Pro. The Business plan costs $300/month ($250/month annually), raising the dashboard seat count to ten, adding a SOC 2 report, priority support, and 30-day application log retention, with volume pricing on MRU overages. Enterprise plans are custom-priced and add a 99.99% uptime SLA, dedicated support, HIPAA compliance with a signed BAA, custom log retention, and SIEM integration. Clerk is best suited for startups and product teams building modern web applications that want to avoid maintaining custom auth infrastructure, particularly teams already using React-based frameworks. Its primary competitors include Auth0, Okta, Firebase Authentication, and Supabase Auth, with Clerk generally positioned as a more developer-experience-focused, UI-component-first alternative relative to older enterprise identity platforms.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '84902cee-488e-4583-aad3-f2fbf318cb9e';

