-- ── ClickHouse ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$ClickHouse is an open-source, column-oriented database built for real-time analytics at scale, available self-hosted for free or as the managed ClickHouse Cloud.$q$, short_description),
  pricing_model = COALESCE($q$Usage-based$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted); ClickHouse Cloud from ~$66/month$q$, starting_price),
  founded_year = COALESCE(2021, founded_year),
  company_size = COALESCE($q$500-1,000 employees$q$, company_size),
  headquarters = COALESCE($q$San Francisco Bay Area, United States (with ClickHouse B.V. in Amsterdam, Netherlands)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$ClickHouse Review: Open-Source Analytics Database & Pricing$q$, seo_title),
  seo_meta_description = COALESCE($q$ClickHouse is an open-source columnar database for real-time analytics. Compare self-hosted vs ClickHouse Cloud pricing, features, and use cases.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$ClickHouse is an open-source, column-oriented database management system built for online analytical processing (OLAP), designed to run SQL queries over very large datasets and return results in real time. The underlying technology originated in 2009 when Alexey Milovidov and collaborators began developing it to power Yandex.Metrica, one of the world's largest web analytics platforms, and it was released as open source in 2016. ClickHouse Inc. was incorporated in San Francisco in September 2021 to commercialize the database, with a subsidiary, ClickHouse B.V., based in Amsterdam, Netherlands, giving the company dual US and European operating bases. Since its open-source release, ClickHouse has been adopted by companies including Uber, Comcast, eBay, and Cisco for high-volume analytics workloads such as observability, product analytics, and real-time reporting. The core database remains free and open source and can be self-hosted on any infrastructure, with no licensing cost, though operating it at scale requires managing the underlying servers, storage, and cluster configuration directly. For teams that prefer a managed offering, ClickHouse Inc. sells ClickHouse Cloud, a serverless, fully managed version of the database billed separately for compute and storage: compute is metered per minute in increments tied to available memory, with rates that increase by tier (roughly $0.22/unit-hour on the Basic tier, $0.30 on Scale, and $0.39 on Enterprise), while storage is billed at a flat rate of roughly $25 per terabyte-month across all tiers. ClickHouse Cloud has three named tiers: Basic, aimed at experimentation and small-scale analytics rather than production high-availability workloads, with realistic monthly costs often in the $66-190 range depending on usage; Scale, starting around $499/month, built for production workloads needing replica and shard scaling; and Enterprise, which adds compliance features like HIPAA/PCI support, SAML/SSO, and customer-managed encryption keys, with typical bills ranging roughly from $2,700 to $9,700/month depending on configuration. New ClickHouse Cloud accounts get a 30-day trial with $300 in credit. The company has raised significant venture funding and reached a valuation in the billions of dollars, with annualized revenue reported at roughly $100 million as ClickHouse Cloud has scaled since its 2022 launch. ClickHouse is best suited for engineering teams building analytics, observability, or reporting systems that need to query billions of rows with low latency, and is generally not the right choice for transactional (OLTP) workloads like typical application databases, where row-oriented systems like PostgreSQL are a better fit.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'd1cc98c8-156a-4960-9e1b-8d537e303a0e';

